targets.query:
from(bucket: "tomcat_jmx_metrics")
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r["_measurement"] == "ndb_operations")
  |> filter(fn: (r) => r["_field"] == "duration_ms")
  |> filter(fn: (r) => r["status"] == "success") // Only measure successful operations
  // Apply the Grafana variables
  |> filter(fn: (r) => r["ndb_ip"] =~ /^${ndb_ip:regex}$/)
  |> filter(fn: (r) => r["engine"] =~ /^${engine:regex}$/)
  |> filter(fn: (r) => r["database_type"] =~ /^${database_type:regex}$/)
  // Group by operation type and NDB version
  |> group(columns: ["operation_type", "ndb_version"])
  // Calculate the average duration in milliseconds
  |> mean()
  // Convert milliseconds to minutes (divide by 60,000)
  |> map(fn: (r) => ({ r with _value: r._value / 60000.0 }))
  |> group()
  // Keep only the necessary columns
  |> keep(columns: ["operation_type", "ndb_version", "_value"])
  // Pivot so that each ndb_version becomes a column
  |> pivot(rowKey: ["operation_type"], columnKey: ["ndb_version"], valueColumn: "_value")
  // Sort alphabetically by operation type
  |> sort(columns: ["operation_type"])
